import subprocess
import re
import shlex

def executeCommand():
    command = input("Enter command: ")
    if not command:
        print("Empty command")
        return
    if re.search(r'[;|&<>()$`]', command):
        print("Invalid command")
        return
    parts = shlex.split(command)
    try:
        subprocess.run(parts, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Command failed: {e}")

